const body = $input.first().json.body || {};
const templates = body.templates || [];
const natures   = body.natures   || [];
const lockedFields = body.lockedFields || {};
const productNames = (body.productNames || []).join(', ') || 'AC, Lift, Water Purifier, Generator, UPS, Fire Panel, CCTV';

// ── Step 1: Strip HTML to plain text
function stripHtml(html) {
  return (html || '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<\/div>/gi, '\n')
    .replace(/<[^>]+>/g, '')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/\r\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

const plainText = stripHtml(body.emailBody || '');

// ── Step 2: Pattern-based extraction
function extract(text, ...patterns) {
  for (const p of patterns) {
    const m = text.match(p);
    if (m && m[1]) return m[1].trim();
  }
  return null;
}

const regexExtracted = {
  storeCode: extract(plainText,
    /(?:site\s*code|store\s*code)[\s:–\-]+([A-Z]{1,3}\d{2,4})/i,
    /\b([A-Z]{2,3}\d{2,3})\b/
  ),
  employeeCode: extract(plainText,
    /employee\s*(?:code|id|no\.?)\s*(?:is\b)?\s*[-:–\-\s]+?(\d{5,7})/i,
    /employee\s*(?:code|id|no\.?)\s*(?:is\b)?\s*[-:–\-\s]+?(VMM\d{3})/i
  ),
  employeeName: extract(plainText,
    /employee\s*name[\s:–\-]+([^\n\r•]+)/i
  ),
  contactNumber: extract(plainText,
    /(?:contact|mobile|phone|registered\s*contact\s*numbers?)[\s:–\-]+([6-9]\d{9})/i,
    /\b([6-9]\d{9})\b/
  ),
  productLocation: extract(plainText,
    /location[\s:–\-]+([^\n\r•]+)/i
  ),
};

// Uppercase the employee code (regex already validates format)
if (regexExtracted.employeeCode) {
  regexExtracted.employeeCode = regexExtracted.employeeCode.toUpperCase();
}

// Validate store code — 1-3 letters + 2-4 digits
if (regexExtracted.storeCode) {
  const sc = regexExtracted.storeCode.toUpperCase();
  if (!/^[A-Z]{1,3}\d{2,4}$/.test(sc)) {
    regexExtracted.storeCode = null;
  } else {
    regexExtracted.storeCode = sc;
  }
}

// ── Step 3: Merge — lockedFields WIN over regex, regex wins over AI
function resolveField(field) {
  const locked = (lockedFields[field] || '').toString().trim();
  if (locked) return locked;
  return regexExtracted[field] || null;
}

const preResolved = {
  storeCode:       resolveField('storeCode'),
  employeeCode:    resolveField('employeeCode'),
  employeeName:    resolveField('employeeName'),
  contactNumber:   resolveField('contactNumber'),
  productLocation: resolveField('productLocation'),
  productName:     (lockedFields.productName    || '').trim() || null,
  natureOfProblem: (lockedFields.natureOfProblem || '').trim() || null,
  description:     (lockedFields.description    || '').trim() || null,
};

// ── Step 4: Build AI prompt — tell AI what is already confirmed
const templateSummary = templates.map(t => {
  const cleanBody = (t.body || '')
    .replace(/<table[\s\S]*?<\/table>/gi, '[TABLE FORMAT REQUIRED]')
    .replace(/<[^>]+>/g, '')
    .replace(/\s+/g, ' ')
    .trim();
  return `ID ${t.id}: ${t.name} (${t.category})\n${cleanBody}`;
}).join('\n---\n').slice(0, 6000);

const natureList = natures.length
  ? natures.map(n => `- ${n.nature} (${n.type})`).join('\n')
  : '(list not provided)';

const confirmedLines = Object.entries(preResolved)
  .filter(([, v]) => v)
  .map(([k, v]) => `  ${k}: "${v}"`)
  .join('\n') || '  (none yet)';

function fieldLine(key, desc, confirmed) {
  return confirmed
    ? `- ${key}: CONFIRMED = "${confirmed}" — return this exact value unchanged`
    : `- ${key}: ${desc}`;
}

const systemPrompt = [
  'You are an assistant for VMM retail store complaint management.',
  'You will receive a full email thread and a list of reply templates.',
  '',
  'CONFIRMED FIELDS — these have already been extracted and verified. Return them EXACTLY as shown, do not change:',
  confirmedLines,
  '',
  'Your tasks:',
  '1. Read the ENTIRE email thread (all messages, not just the latest)',
  '2. Select the best matching reply template',
  '3. Fill in ONLY the fields that are still missing (null)',
  '4. Draft a reply ONLY if storeCode or employeeCode is still missing',
  '',
  'Return valid JSON with ALL these keys:',
  fieldLine('storeCode', 'string or null — extract from "Site Code:" or "Store Code:" label (e.g. HN28, SF90, HP17)', preResolved.storeCode),
  fieldLine('employeeCode', 'string or null — valid formats ONLY: 5-7 digit number (e.g. 201838, 77199) OR VMM followed by 3 digits (e.g. VMM080, VMM663). Do NOT use 10-digit phone numbers.', preResolved.employeeCode),
  fieldLine('employeeName', 'string or null — only if explicitly labelled as employee name in the email body', preResolved.employeeName),
  fieldLine('contactNumber', 'string or null — 10-digit mobile number', preResolved.contactNumber),
  fieldLine('productLocation', 'string or null — city/area from Location field', preResolved.productLocation),
  fieldLine('productName', `string or null — MUST be chosen EXACTLY from this list (match by meaning, e.g.

const raw = $input.first().json;
const preResolved = $('Prepare Template Context').first().json.preResolved || {};
const content = raw?.choices?.[0]?.message?.content || '{}';

let parsed = {};
try {
  parsed = JSON.parse(content);
} catch {
  parsed = { description: content, missingFromTemplate: [], suggestedReply: '', isComplete: false };
}

// Enforce pre-resolved fields — locked/regex values always win over AI output
for (const [field, value] of Object.entries(preResolved)) {
  if (value) parsed[field] = value;
}

// Recompute isComplete based on final merged values
parsed.isComplete = !!(parsed.storeCode && parsed.employeeCode);

// If now complete, clear suggested reply
if (parsed.isComplete) parsed.suggestedReply = '';

parsed.missingFromTemplate = Array.isArray(parsed.missingFromTemplate) ? parsed.missingFromTemplate : [];

return [{ json: { success: true, ...parsed } }];
